, "content": "'use client';

import { useState } from 'react';
import ScenarioForm from '@/components/ScenarioForm';
import TestExecutor from '@/components/TestExecutor';
import ComparisonView from '@/components/ComparisonView';
import { TestScenario, TestResult, ComparisonResult } from '@/lib/types';

export default function Home() {
  const [currentTab, setCurrentTab] = useState<'create' | 'execute' | 'compare'>('create');
  const [scenario, setScenario] = useState<TestScenario | null>(null);
  const [asIsResult, setAsIsResult] = useState<TestResult | null>(null);
  const [toBeResult, setToBeResult] = useState<TestResult | null>(null);
  const [comparisonResult, setComparisonResult] = useState<ComparisonResult | null>(null);

  const handleScenarioCreate = (newScenario: TestScenario) => {
    setScenario(newScenario);
    setCurrentTab('execute');
  };

  const handleAsIsComplete = (result: TestResult) => {
    setAsIsResult(result);
  };

  const handleToBeComplete = (result: TestResult) => {
    setToBeResult(result);
  };

  const handleCompare = (result: ComparisonResult) => {
    setComparisonResult(result);
    setCurrentTab('compare');
  };

  return (
    <div className="py-8">
      {/* �꺆 �꽕鍮꾧쾶�씠�뀡 */}
      <div className="px-4 mb-8 border-b border-gray-200">
        <div className="max-w-7xl mx-auto flex gap-4">
          <button
            onClick={() => setCurrentTab('create')}
            className={`px-4 py-3 font-semibold border-b-2 transition-colors ${
              currentTab === 'create'
                ? 'border-blue-600 text-blue-600'
                : 'border-transparent text-gray-600 hover:text-gray-900'
            }`}
          >
            1截뤴깵 Test Scenario
          </button>
          <button
            onClick={() => setCurrentTab('execute')}
            disabled={!scenario}
            className={`px-4 py-3 font-semibold border-b-2 transition-colors ${
              currentTab === 'execute'
                ? 'border-blue-600 text-blue-600'
                : 'border-transparent text-gray-600 hover:text-gray-900 disabled:opacity-50 disabled:cursor-not-allowed'
            }`}
          >
            2截뤴깵 Execute Tests
          </button>
          <button
            onClick={() => setCurrentTab('compare')}
            disabled={!asIsResult || !toBeResult}
            className={`px-4 py-3 font-semibold border-b-2 transition-colors ${
              currentTab === 'compare'
                ? 'border-blue-600 text-blue-600'
                : 'border-transparent text-gray-600 hover:text-gray-900 disabled:opacity-50 disabled:cursor-not-allowed'
            }`}
          >
            3截뤴깵 Compare Results
          </button>
        </div>
      </div>

      {/* 肄섑뀗痢� */}
      <div className="px-4">
        {currentTab === 'create' && <ScenarioForm onScenarioCreate={handleScenarioCreate} />}

        {currentTab === 'execute' && scenario && (
          <TestExecutor
            scenario={scenario}
            onAsIsComplete={handleAsIsComplete}
            onToBeComplete={handleToBeComplete}
            onCompare={handleCompare}
            asIsResult={asIsResult}
            toBeResult={toBeResult}
          />
        )}

        {currentTab === 'compare' && comparisonResult && (
          <ComparisonView result={comparisonResult} />
        )}
      </div>
    </div>
  );
}
