  const [actions, setActions] = useState<TestAction[]>([]);
  const [jsonInput, setJsonInput] = useState('');
  const [inputMode, setInputMode] = useState<'form' | 'json'>('form');

  const handleFormChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleAddAction = (action: TestAction) => {
    setActions((prev) => [...prev, action]);
  };

  const handleRemoveAction = (index: number) => {
    setActions((prev) => prev.filter((_, i) => i !== index));
  };

  const handleLoadJson = () => {
    try {
      const parsed = JSON.parse(jsonInput);
      if (parsed.name && parsed.baseUrl && Array.isArray(parsed.actions)) {
        setFormData({
          name: parsed.name,
          description: parsed.description || '',
          baseUrl: parsed.baseUrl,
        });
        setActions(parsed.actions);
        setInputMode('form');
        alert('�쐟 JSON loaded successfully!');
      } else {
        alert('�쓬 Invalid JSON format. Required: name, baseUrl, actions[]');
      }
    } catch (error) {
      alert(`�쓬 JSON parsing failed: ${error instanceof Error ? error.message : 'Unknown error'}`);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!formData.name || !formData.baseUrl || actions.length === 0) {
      alert('�쓬 Please fill in all required fields and add at least one action');
      return;
    }

    const scenario: TestScenario = {
      id: `scenario_${Date.now()}`,
      name: formData.name,
      description: formData.description,
      baseUrl: formData.baseUrl,
      actions,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    };

    onScenarioCreate(scenario);
  };

  const handleExportJson = () => {
    const scenario = {
      name: formData.name,
      description: formData.description,
      baseUrl: formData.baseUrl,
      actions,
    };
    const json = JSON.stringify(scenario, null, 2);
    const blob = new Blob([json], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
