export default function ResultViewer({ result }: ResultViewerProps) {
  const [expandedIndex, setExpandedIndex] = useState<number | null>(null);

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'passed':
        return 'bg-green-100 text-green-800 badge-success';
      case 'error':
        return 'bg-red-100 text-red-800 badge-error';
      case 'failed':
        return 'bg-yellow-100 text-yellow-800 badge-warning';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  return (
    <div className="space-y-4">
      {/* 寃곌낵 �슂�빟 */}
      <div className="bg-gray-50 p-4 rounded-lg border border-gray-200">
        <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
          <div>
            <span className="text-sm text-gray-600">Status</span>
            <p className={`font-bold text-lg badge ${getStatusColor(result.status)}`}>
              {result.status.toUpperCase()}
            </p>
          </div>
          <div>
            <span className="text-sm text-gray-600">Duration</span>
            <p className="font-bold text-lg">{result.executionTime}ms</p>
          </div>
          <div>
            <span className="text-sm text-gray-600">Actions</span>
            <p className="font-bold text-lg">{result.results.length}</p>
          </div>
        </div>
      </div>

      {/* �븸�뀡 寃곌낵 */}
