        <h4 className="font-semibold mb-3">Action Results</h4>
        <div className="space-y-2">
          {result.results.map((actionResult, index) => (
            <div key={index} className="border border-gray-200 rounded-lg">
              <button
                onClick={() => setExpandedIndex(expandedIndex === index ? null : index)}
                className="w-full text-left p-4 hover:bg-gray-50 transition-colors flex items-center justify-between"
              >
                <div className="flex-1">
                  <div className="flex items-center gap-3">
                    <span className={`badge ${getStatusColor(actionResult.status)}`}>
                      {actionResult.status.toUpperCase()}
                    </span>
                    <span className="font-semibold text-blue-600">
                      {actionResult.action.type}
                    </span>
                    {actionResult.action.description && (
                      <span className="text-gray-600">
                        - {actionResult.action.description}
                      </span>
                    )}
                  </div>
                </div>
                <span className="text-gray-400">
                  {expandedIndex === index ? '�뼹' : '�뼳'}
                </span>
              </button>

              {expandedIndex === index && (
                <div className="px-4 pb-4 bg-gray-50 border-t border-gray-200">
                  {/* �븸�뀡 �긽�꽭 �젙蹂� */}
                  <div className="mb-3">
                    <p className="text-sm font-semibold text-gray-700 mb-1">Action Details:</p>
                    <pre className="code-block text-xs overflow-auto">
                      {JSON.stringify(actionResult.action, null, 2)}
                    </pre>
                  </div>

                  {/* 異쒕젰 寃곌낵 */}
