export interface TestAction {
  type: 'navigate' | 'click' | 'fill' | 'select' | 'screenshot' | 'wait' | 'evaluate';
  selector?: string;
  text?: string;
  url?: string;
  milliseconds?: number;
  script?: string;
  description?: string;
}

export interface TestScenario {
  id: string;
  name: string;
  description: string;
  baseUrl: string;
  actions: TestAction[];
  expectedOutputs?: ExpectedOutput[];
  createdAt: string;
  updatedAt: string;
}

export interface ExpectedOutput {
  type: 'text' | 'url' | 'element' | 'api' | 'custom';
  selector?: string;
  expectedValue: string | Record<string, any>;
  description?: string;
}

export interface TestResult {
  scenarioId: string;
  scenarioName: string;
  version: 'as-is' | 'to-be';
  status: 'passed' | 'failed' | 'error';
  executionTime: number;
  results: ActionResult[];
  screenshots?: string[];
  error?: string;
  executedAt: string;
}

export interface ActionResult {
  action: TestAction;
  status: 'passed' | 'failed' | 'error';
  output?: any;
  error?: string;
  screenshot?: string;
}

export interface ComparisonResult {
  scenarioId: string;
  scenarioName: string;
  status: 'identical' | 'different' | 'error';
  asIsResult: TestResult;
  toBeResult: TestResult;
  differences: Difference[];
  comparisonReport: string;
  comparedAt: string;
}

export interface Difference {
  actionIndex: number;
  actionDescription: string;
  asIsOutput: any;
  toBeOutput: any;
  severity: 'critical' | 'warning' | 'info';
  message: string;
}

export interface ApiResponse<T> {
  success: boolean;
  data?: T;
  error?: string;
  message?: string;
}
