  const [comparisonResult, setComparisonResult] = useState<ComparisonResult | null>(null);

  const handleScenarioCreate = (newScenario: TestScenario) => {
    setScenario(newScenario);
    setCurrentTab('execute');
  };

  const handleAsIsComplete = (result: TestResult) => {
    setAsIsResult(result);
  };

  const handleToBeComplete = (result: TestResult) => {
    setToBeResult(result);
  };

  const handleCompare = (result: ComparisonResult) => {
    setComparisonResult(result);
    setCurrentTab('compare');
  };

